import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import { Users, RefreshCw, AlertCircle, Database, ShieldCheck, Plus, Minus, Search } from 'lucide-react';

const API_BASE = "https://cna-finance-api.onrender.com/api";

function AdminDashboard() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState(''); // Estado para o filtro de busca
  const [amounts, setAmounts] = useState({});

  const fetchUsers = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const response = await axios.get(`${API_BASE}/admin/users`);
      if (Array.isArray(response.data)) {
        setUsers(response.data);
      }
    } catch (err) {
      setError('Erro ao conectar com a API Administrativa.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchUsers();
  }, [fetchUsers]);

  // Filtra os usuários com base no termo de pesquisa
  const filteredUsers = users.filter(user => 
    user.username.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleInputChange = (userId, value) => {
    setAmounts({ ...amounts, [userId]: value });
  };

  const handleUpdateBalance = async (userId, type) => {
    const value = parseFloat(amounts[userId]);
    if (!value || value <= 0) {
      alert("Digite um valor válido.");
      return;
    }

    const finalAmount = type === 'add' ? value : -value;

    try {
      await axios.post(`${API_BASE}/admin/update-balance`, {
        user_id: userId,
        amount: finalAmount
      });
      handleInputChange(userId, '');
      fetchUsers(); 
    } catch (err) {
      alert("Erro ao atualizar saldo.");
    }
  };

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <div style={styles.titleGroup}>
          <ShieldCheck color="#E50136" size={24} />
          <h2 style={styles.title}>Painel Administrativo</h2>
        </div>
        <button onClick={fetchUsers} style={styles.refreshBtn} disabled={loading}>
          <RefreshCw size={16} style={{ animation: loading ? 'spin 1s linear infinite' : 'none' }} />
          {loading ? 'Sincronizando...' : 'Atualizar'}
        </button>
      </header>

      {/* BARRA DE PESQUISA */}
      <div style={styles.searchContainer}>
        <Search size={18} color="#94a3b8" style={styles.searchIcon} />
        <input 
          type="text" 
          placeholder="Pesquisar usuário por nome..." 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          style={styles.searchInput}
        />
      </div>

      <div style={styles.statsRow}>
        <div style={styles.statCard}>
          <Users size={20} color="#94a3b8" />
          <div>
            <p style={styles.statLabel}>Contas Ativas</p>
            <p style={styles.statValue}>{users.length}</p>
          </div>
        </div>
        <div style={styles.statCard}>
          <Database size={20} color="#94a3b8" />
          <div>
            <p style={styles.statLabel}>Total em Circulação</p>
            <p style={styles.statValue}>
              CNA$ {users.reduce((acc, u) => acc + (u.balance || 0), 0).toFixed(2)}
            </p>
          </div>
        </div>
      </div>

      <div style={styles.tableContainer}>
        <table style={styles.table}>
          <thead>
            <tr>
              <th style={styles.th}>Usuário</th>
              <th style={styles.th}>Saldo</th>
              <th style={{...styles.th, textAlign: 'center'}}>Ajustar Saldo</th>
            </tr>
          </thead>
          <tbody>
            {filteredUsers.map((u) => (
              <tr key={u.id} style={styles.tr}>
                <td style={styles.td}>
                  <div style={{fontWeight: 'bold'}}>{u.username}</div>
                  <div style={{fontSize: '10px', color: '#64748b'}}>{u.role.toUpperCase()}</div>
                </td>
                <td style={{...styles.td, color: '#10b981', fontWeight: 'bold'}}>
                  CNA$ {(u.balance || 0).toFixed(2)}
                </td>
                <td style={{...styles.td, textAlign: 'center'}}>
                  <div style={styles.actionGroup}>
                    <input 
                      type="number"
                      placeholder="Valor"
                      value={amounts[u.id] || ''}
                      onChange={(e) => handleInputChange(u.id, e.target.value)}
                      style={styles.inputAmount}
                    />
                    <button onClick={() => handleUpdateBalance(u.id, 'rem')} style={styles.btnMinus} title="Subtrair"><Minus size={14} /></button>
                    <button onClick={() => handleUpdateBalance(u.id, 'add')} style={styles.btnPlus} title="Adicionar"><Plus size={14} /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {filteredUsers.length === 0 && (
          <div style={styles.emptyMsg}>Nenhum usuário encontrado com "{searchTerm}"</div>
        )}
      </div>

      <style>{`
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
      `}</style>
    </div>
  );
}

const styles = {
  container: { marginTop: '10px' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' },
  titleGroup: { display: 'flex', alignItems: 'center', gap: '10px' },
  title: { fontSize: '18px', margin: 0, color: 'white', fontWeight: '800' },
  refreshBtn: { display: 'flex', alignItems: 'center', gap: '8px', backgroundColor: '#1e293b', border: '1px solid #334155', color: '#94a3b8', padding: '8px 15px', borderRadius: '8px', cursor: 'pointer' },
  
  // Estilo da Busca
  searchContainer: { position: 'relative', marginBottom: '20px', display: 'flex', alignItems: 'center' },
  searchIcon: { position: 'absolute', left: '15px' },
  searchInput: { width: '100%', backgroundColor: '#1e293b', border: '1px solid #334155', color: 'white', padding: '12px 12px 12px 45px', borderRadius: '12px', outline: 'none', fontSize: '14px' },
  
  statsRow: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px', marginBottom: '20px' },
  statCard: { backgroundColor: '#1e293b', padding: '15px', borderRadius: '15px', display: 'flex', alignItems: 'center', gap: '12px', border: '1px solid #334155' },
  statLabel: { color: '#94a3b8', fontSize: '10px', margin: 0, textTransform: 'uppercase' },
  statValue: { color: 'white', fontSize: '16px', fontWeight: 'bold', margin: 0 },
  tableContainer: { backgroundColor: '#1e293b', borderRadius: '20px', border: '1px solid #334155', overflow: 'hidden' },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: { textAlign: 'left', padding: '15px', backgroundColor: '#0f172a', color: '#94a3b8', fontSize: '11px', textTransform: 'uppercase' },
  tr: { borderBottom: '1px solid #334155' },
  td: { padding: '15px', color: '#f8fafc', fontSize: '13px' },
  actionGroup: { display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '8px' },
  inputAmount: { width: '70px', backgroundColor: '#0f172a', border: '1px solid #334155', color: 'white', padding: '6px', borderRadius: '6px', fontSize: '12px', textAlign: 'center' },
  btnPlus: { backgroundColor: '#10b981', color: 'white', border: 'none', borderRadius: '6px', padding: '6px', cursor: 'pointer' },
  btnMinus: { backgroundColor: '#E50136', color: 'white', border: 'none', borderRadius: '6px', padding: '6px', cursor: 'pointer' },
  emptyMsg: { textAlign: 'center', padding: '20px', color: '#94a3b8', fontSize: '14px' }
};

export default AdminDashboard;
